// Fichas activas (sin soft-delete)
const fichas = $('GET Fichas').all().map(i => i.json).filter(f => f && f.id && !f.deleted_at);

// Cuenta locales por ficha (tolerante a errores: si la tabla locales
// fallara, simplemente quedan a 0).
const locales = ($('GET Locales').all() || [])
  .map(i => (i && i.json) ? i.json : i)
  .filter(l => l && l.ficha_id);

const conteo = {};
for (const l of locales) {
  conteo[l.ficha_id] = (conteo[l.ficha_id] || 0) + 1;
}

// Enriquecer implementador desde otras tablas cuando fichas_alta lo
// tenga vacío. Orden de prioridad:
//   1. distribucion (workflow 06 escribe aquí al asignar)
//   2. proyectos    (si ya hay proyecto creado, es la fuente de verdad)
// Se hace como fallback: si la ficha ya tiene implementador propio, no
// lo pisamos. Esto evita que una reasignación en fichas_alta quede
// sobreescrita por un snapshot obsoleto de otra tabla.
const distri = ($('GET Distribución').all() || [])
  .map(i => (i && i.json) ? i.json : i)
  .filter(d => d && d.ficha_id && d.implementador);
const implPorDistri = {};
for (const d of distri) {
  const prev = implPorDistri[d.ficha_id];
  const dts  = d.created_at ? new Date(d.created_at).getTime() : 0;
  if (!prev || dts >= prev.ts) implPorDistri[d.ficha_id] = { impl: d.implementador, ts: dts };
}

// Para el fallback de implementador descartamos proyectos completados.
// Para exponer el estado del proyecto al frontend, sin embargo, TODOS los
// proyectos son relevantes (un cliente completado debería mostrar
// "Completado" en la columna "Estado implementación"). Indexamos dos
// mapas distintos: uno solo-activos para implementador, otro all-states
// para proyecto_estado.
const proysTodos = ($('GET Proyectos').all() || [])
  .map(i => (i && i.json) ? i.json : i)
  .filter(p => p && !p.deleted_at);

const implPorProy = {};
const implPorCliente = {};
const estadoPorProy = {};
const estadoPorCliente = {};
for (const p of proysTodos) {
  const dts = p.ultima_actividad ? new Date(p.ultima_actividad).getTime()
            : (p.fecha_inicio ? new Date(p.fecha_inicio).getTime() : 0);
  const clienteKey = p.cliente ? String(p.cliente).trim().toLowerCase() : '';
  // Estado: siempre el registro más reciente gana, esté completado o no.
  if (p.estado) {
    if (p.ficha_id) {
      const prev = estadoPorProy[p.ficha_id];
      if (!prev || dts >= prev.ts) estadoPorProy[p.ficha_id] = { estado: p.estado, ts: dts };
    }
    if (clienteKey) {
      const prev = estadoPorCliente[clienteKey];
      if (!prev || dts >= prev.ts) estadoPorCliente[clienteKey] = { estado: p.estado, ts: dts };
    }
  }
  // Implementador: sólo desde proyectos activos/pausados (no completados).
  if (p.implementador && p.estado !== 'completado') {
    if (p.ficha_id) {
      const prev = implPorProy[p.ficha_id];
      if (!prev || dts >= prev.ts) implPorProy[p.ficha_id] = { impl: p.implementador, ts: dts };
    }
    if (clienteKey) {
      const prev = implPorCliente[clienteKey];
      if (!prev || dts >= prev.ts) implPorCliente[clienteKey] = { impl: p.implementador, ts: dts };
    }
  }
}

function _normCliente(s) { return String(s || '').trim().toLowerCase(); }
for (const f of fichas) {
  f.locales_count = conteo[f.id] || 0;
  const nombres = [f.nombre_comercial, f.denominacion].filter(Boolean).map(_normCliente);

  // Implementador — fallback si fichas_alta no lo tiene propio.
  if (!f.implementador || !String(f.implementador).trim()) {
    let hit = implPorDistri[f.id] || implPorProy[f.id] || null;
    for (const n of nombres) {
      if (hit) break;
      if (implPorCliente[n]) hit = implPorCliente[n];
    }
    if (hit) f.implementador = hit.impl;
  }

  // Estado del proyecto de implementación — consumido por clientes.html
  // en la columna "Estado implementación". Puede ser activo | pausado |
  // completado o null si el cliente aún no tiene proyecto.
  let estHit = estadoPorProy[f.id] || null;
  for (const n of nombres) {
    if (estHit) break;
    if (estadoPorCliente[n]) estHit = estadoPorCliente[n];
  }
  f.proyecto_estado = estHit ? estHit.estado : null;
}

return [{ json: { clientes: fichas } }];

const d = $input.first().json.body;

const rawId = d.id;
const cleanId = (rawId == null || rawId === 'undefined' || rawId === 'null' || String(rawId).trim() === '') ? null : rawId;
const isEdit = !!cleanId;

const row = {};
if (isEdit) row.id = cleanId;

// Helper: en edición sólo seteamos los campos que vienen en el payload
// (clave existe, no es undefined). Antes hacíamos `row.x = d['X'] || ''`
// para todos, lo que pisaba con cadena vacía cualquier campo no enviado al
// hacer un guardado parcial (p.ej. toggle A3, marcar estado, etc.).
function set(col, ...keys) {
  for (const k of keys) {
    if (Object.prototype.hasOwnProperty.call(d, k) && d[k] !== undefined) {
      row[col] = d[k];
      return true;
    }
  }
  return false;
}

set('comercial',         'Comercial');
set('denominacion',      'Nombre Sociedad', 'Denominación Social');
set('nombre_comercial',  'Nombre Comercial');
set('calle',             'Calle');
set('numero',            'Número');
if (set('cp', 'CP')) row.cp = row.cp || null;
set('municipio',         'Municipio');
set('provincia',         'Provincia');
set('cif',               'CIF/NIF');
set('email',             'Email');
set('email_factura',     'Email Factura');
set('email_cc',          'Email CC');
set('iban',              'IBAN');
if (set('tipo_cliente',  'Tipo Cliente')) row.tipo_cliente = row.tipo_cliente || null;
set('firmas_contratadas','Firmas Contratadas');
set('jp_nombre',         'JP Nombre');
set('jp_apellidos',      'JP Apellidos');
set('jp_rol',            'JP Rol');
set('jp_telefono',       'JP Teléfono');
set('jp_mail',           'JP Mail');
set('firm_nombre',       'Firmante Nombre');
set('firm_apellidos',    'Firmante Apellidos');
set('firm_mail',         'Firmante Mail');
set('firm_dni',          'Firmante DNI');
set('firm_puesto',       'Firmante Puesto');
set('tpv',               'TPV');
set('tpv_contacto',      'TPV Contacto');
set('tpv_email',         'TPV Email');
if (Object.prototype.hasOwnProperty.call(d, 'TPV No Integrado')) row.tpv_no_integrado = d['TPV No Integrado'] === 'Sí';
set('tpv_ni_nombre',     'TPV NI Nombre');
set('tpv_ni_contacto',   'TPV NI Contacto');
set('tpv_ni_email',      'TPV NI Email');
if (Object.prototype.hasOwnProperty.call(d, 'Lite')) row.lite = (d['Lite'] === 'Sí');
set('entrega_calle',     'Entrega Calle');
set('entrega_numero',    'Entrega Número');
if (set('entrega_cp',    'Entrega CP')) row.entrega_cp = row.entrega_cp || null;
set('entrega_municipio', 'Entrega Municipio');
set('entrega_provincia', 'Entrega Provincia');
set('contacto_nombre',   'Contacto Nombre');
set('contacto_email',    'Contacto Email');
set('contacto_telefono', 'Contacto Teléfono');
if (Object.prototype.hasOwnProperty.call(d, 'Distribuidor')) row.distribuidor = (d['Distribuidor'] === 'Sí');
set('dist_empresa',      'Dist. Empresa');
set('dist_cif',          'Dist. CIF');
set('dist_direccion',    'Dist. Dirección');
set('dist_cp',           'Dist. CP');
set('dist_contacto',     'Dist. Contacto');
set('dist_mail',         'Dist. Mail');
set('dist_telefono',     'Dist. Teléfono');
if (Object.prototype.hasOwnProperty.call(d, 'Dist. Comisión Implementación (%)')) row.dist_comision = parseFloat(d['Dist. Comisión Implementación (%)']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'ImporteSetup'))               row.importe_setup = parseFloat(d['ImporteSetup']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Descuentosetup'))             row.descuento_setup = parseFloat(d['Descuentosetup']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Mensualidad Total Locales')) {
  row.mensualidad_total_locales = parseFloat(d['Mensualidad Total Locales']) || 0;
  row.mensualidad_total         = parseFloat(d['Mensualidad Total Locales']) || 0;
}
if (Object.prototype.hasOwnProperty.call(d, 'Proyecto de Implementación')) row.fin_implementacion    = parseFloat(d['Proyecto de Implementación']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Producto BASIC'))        row.fin_basic             = parseFloat(d['Plan Producto BASIC']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Producto PRO'))          row.fin_pro               = parseFloat(d['Plan Producto PRO']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan RRHH'))                  row.fin_rrhh              = parseFloat(d['Plan RRHH']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Plan Operaciones'))           row.fin_operaciones       = parseFloat(d['Plan Operaciones']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Yurest Lite'))                row.fin_lite              = parseFloat(d['Yurest Lite']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Integraciones'))              row.fin_integraciones     = parseFloat(d['Integraciones']) || 0;
if (Object.prototype.hasOwnProperty.call(d, 'Mensualidad Anualizada'))     row.fin_mensualidad_anual = parseFloat(d['Mensualidad Anualizada']) || 0;

if (d.paquetes_carrito !== undefined) row.paquetes_carrito = d.paquetes_carrito;

set('cred_master',   'Credencial Master');
set('cred_yurest',   'Credencial Yurest');

// Integración financiera: slug normalizado + contactos opcionales.
// El CHECK de la columna acepta solo 'no_aplica' | 'sage' | 'a3' | NULL,
// así que normalizamos por si llegase mayúsculas/espacios desde el front.
if (Object.prototype.hasOwnProperty.call(d, 'Integracion Financiera')) {
  const raw = String(d['Integracion Financiera'] || '').toLowerCase().trim();
  const v = raw === 'sage' ? 'sage'
          : raw === 'a3'   ? 'a3'
          : (raw === 'no_aplica' || raw === 'no aplica' || raw === 'noaplica') ? 'no_aplica'
          : null;
  row.integracion_financiera = v;
}
set('int_fin_persona', 'Int Fin Persona');
set('int_fin_email',   'Int Fin Email');
set('comentarios',   'Comentarios');
set('modulos',       'Módulos');
set('baja',          'Baja');

// OJO: adjuntos y sepa_mandato son JSONB. NO hacer JSON.stringify aquí
// — el nodo Supabase volverá a serializar, guardando un string escalar
// en lugar de objeto/array. Rompe jsonb_set y el trigger asignar_sepa_ref
// con \"cannot set path in scalar\". Pasamos el valor nativo.
if (Array.isArray(d['Adjuntos'])) row.adjuntos = d['Adjuntos'];
else if (Array.isArray(d.adjuntos)) row.adjuntos = d.adjuntos;

if (d['SEPA'] && typeof d['SEPA'] === 'object') row.sepa_mandato = d['SEPA'];
else if (d.sepa_mandato && typeof d.sepa_mandato === 'object') row.sepa_mandato = d.sepa_mandato;

if (d['Estado']) row.estado = String(d['Estado']).toLowerCase();

// En alta nueva, garantizar defaults para columnas NOT NULL.
if (!isEdit) {
  if (row.denominacion == null) row.denominacion = '';
  if (row.modulos == null)      row.modulos = [];
  if (row.baja == null)         row.baja = 'No';
}

const locales = d.locales || [];

return [{ json: { row, locales, isEdit } }];

// Construye el body de la PATCH y separa id del resto.
// No podemos incluir id en el SET de PostgREST porque intenta
// actualizar la PK (incluso al mismo valor) y algunas
// configuraciones RLS lo rechazan silenciosamente → el UPDATE
// devuelve 0 filas afectadas aunque el HTTP sea 200.
const { row } = $input.first().json;
const id = row.id;
const body = { ...row };
delete body.id;
// Limpiamos undefined por si acaso (PostgREST los envía como null)
Object.keys(body).forEach(k => { if (body[k] === undefined) delete body[k]; });
return [{ json: { id, __body: JSON.stringify(body) } }];

// INSERT: extraer row sin id
const { row } = $input.first().json;
delete row.id;
return [{ json: row }];

// Lee locales y ficha_id directamente del node 'Preparar Ficha'
// para ser robusto al cambio de topología: ahora este node
// puede recibir input desde DELETE Locales antiguos (UPDATE
// path) o desde INSERT Ficha (INSERT path). En ambos casos el
// id real de la ficha vive en Preparar Ficha o en INSERT Ficha.
const prep = $('Preparar Ficha').first().json || {};
const row = prep.row || {};
const locales = prep.locales || [];

// Si fue INSERT, la ficha recién creada tiene id en el output
// del node 'INSERT Ficha'. Si fue UPDATE, el id ya venía en
// row.id (se mandó en el body). Cubrimos ambos.
let fichaId = row.id || null;
if (!fichaId) {
  try {
    const ins = $('INSERT Ficha').first();
    if (ins && ins.json && ins.json.id) fichaId = ins.json.id;
  } catch (_) {}
}
if (!fichaId) {
  // Sin id no podemos insertar locales — mejor no hacerlo que
  // crear filas huérfanas.
  return [];
}
if (!Array.isArray(locales) || locales.length === 0) return [];

// Helpers de saneado.
// 1) `nullable`: convierte '' / null / undefined → null para columnas que
//    aceptan NULL pero NO string vacío (CHECKs como cp regex fallarían).
// 2) `cpOrNull`: además valida 5 dígitos; si no, va NULL para evitar
//    violar el CHECK. (El front ya valida, esto es defensivo.)
const nullable  = v => (v == null || v === '') ? null : String(v).trim() || null;
const cpOrNull  = v => {
  const s = (v == null) ? '' : String(v).trim();
  return /^\d{5}$/.test(s) ? s : null;
};

const rows = locales.map(l => ({
  ficha_id: fichaId,
  // nombre es NOT NULL en la tabla; si llegara vacío preferimos un valor
  // por defecto en lugar de fallar. El front debería evitar este caso.
  nombre: (l.nombre && String(l.nombre).trim()) || 'Local sin nombre',
  email:  nullable(l.email),
  calle:  nullable(l.calle),
  numero: nullable(l.numero),
  cp:     cpOrNull(l.cp),
  sociedad_cif:          nullable(l.sociedad_cif),
  sociedad_denominacion: nullable(l.sociedad_denominacion),
  sociedad_calle:        nullable(l.sociedad_calle),
  sociedad_numero:       nullable(l.sociedad_numero),
  sociedad_cp:           nullable(l.sociedad_cp),
  sociedad_municipio:    nullable(l.sociedad_municipio),
  sociedad_provincia:    nullable(l.sociedad_provincia),
  mensualidad: parseFloat(l.mensualidad) || 0,
  // sepa_mandato_id es UUID en BD: rechazamos cualquier cosa que no
  // sea UUID v1-5 (ej. referencias legacy 'YUREST-2026-0006' o ids
  // sintéticos 'sepa-0' que el front pudiera no haber filtrado).
  sepa_mandato_id: (function(v){
    return (typeof v === 'string' && /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(v)) ? v : null;
  })(l.sepa_mandato_id),
  es_cocina_central: l.es_cocina_central === true || l.es_cocina_central === 'true'
}));
return rows.map(r => ({ json: r }));

// Verifica que la PATCH de UPDATE Ficha devolvió al menos una
// fila. Si devuelve array vacío, el id no existía (o la
// política RLS no dejó) — lo anunciamos con success:false para
// que el front muestre error en vez de un engañoso "guardado".
const items = $input.all() || [];
let rows = [];
const errores = [];
for (const it of items) {
  const j = (it && it.json) ? it.json : it;
  if (!j) continue;
  // HTTP Request con fullResponse:false devuelve el body directo.
  // Si PostgREST PATCH tuvo éxito con return=representation, es array.
  if (Array.isArray(j)) { rows = rows.concat(j); continue; }
  if (j.error) { errores.push(String(j.error.message || j.error)); continue; }
  if (j.code && j.message) { errores.push(String(j.message)); continue; }
  // Algún formato inesperado: lo guardamos por si acaso.
  if (j.id) rows.push(j);
}
if (rows.length === 0) {
  const prep = $('Preparar Ficha').first().json || {};
  const idIntentado = (prep.row && prep.row.id) || '?';
  errores.push('UPDATE no afectó a ninguna fila. id=' + idIntentado + '. Verifica que el ficha existe y las políticas RLS permiten UPDATE.');
}
// Emitimos siempre una fila con { id } para que los siguientes
// nodos (DELETE locales, Preparar Locales) tengan el id a mano.
const prep2 = $('Preparar Ficha').first().json || {};
const fichaId = (rows[0] && rows[0].id) || (prep2.row && prep2.row.id);
return [{ json: { id: fichaId, __updated: rows.length, __errores: errores } }];

// Último paso antes de responder al front. Recopila:
//   · Errores de Verificar UPDATE (UPDATE devolvió 0 filas)
//   · Errores de INSERT Locales (si lo hubo)
// Si hay errores, success=false. Si no, success=true y
// devolvemos el id de la ficha.
const errores = [];
try {
  const v = $('Verificar UPDATE').first();
  if (v && v.json && Array.isArray(v.json.__errores)) errores.push(...v.json.__errores);
} catch (_) {}

// Extrae un mensaje legible de cualquier formato de error que devuelva
// el nodo Supabase. Hemos visto al menos cuatro variantes según versión:
//   · { error: 'string' }
//   · { error: { message, code, details, hint } }
//   · { code, message, details, hint }   (PostgREST plano)
//   · { errorDetails: { ... } }          (n8n envoltorio cuando continueOnFail)
function _msgError(j) {
  if (!j) return null;
  // 1) j.error como string u objeto
  if (j.error) {
    if (typeof j.error === 'string') return j.error;
    const m = j.error.message || j.error.msg || j.error.detail || j.error.details || j.error.hint;
    if (m) return j.error.code ? (m + ' [' + j.error.code + ']') : m;
    if (j.error.code) return 'código ' + j.error.code;
  }
  // 2) PostgREST plano (no tiene id propio aunque sea un INSERT)
  if (j.code && j.message && !j.id) {
    return j.message + (j.details ? ' (' + j.details + ')' : '') + ' [' + j.code + ']';
  }
  // 3) errorDetails de n8n
  if (j.errorDetails) {
    try { return JSON.stringify(j.errorDetails).slice(0, 300); } catch (_) {}
  }
  return null;
}

// INSERT Locales: examinar items por error.
try {
  const items = $('INSERT Locales').all() || [];
  for (const it of items) {
    const j = (it && it.json) ? it.json : it;
    const m = _msgError(j);
    if (m) errores.push('INSERT Locales: ' + m);
  }
} catch (_) {}

const prep = $('Preparar Ficha').first().json || {};
let fichaId = (prep.row && prep.row.id) || null;
if (!fichaId) {
  try {
    const ins = $('INSERT Ficha').first();
    if (ins && ins.json && ins.json.id) fichaId = ins.json.id;
  } catch (_) {}
}
return [{ json: { success: errores.length === 0, id: fichaId, errores } }];
